__kernel void dynproc_kernel(
    const int pyramid_height,
    __global const int* wall,
    __global int* src,
    __global int* dst,
    const int cols,
    const int rows,
    const int t,
    const int borderCols,
    const int theHalo,
    __local int* localSrc1,
    __local int* localSrc2,
    __global int* outputBuffer)
{
    int n = get_global_id(0);
    int local_id = get_local_id(0);
    int local_size = get_local_size(0);

    // Each iteration of pyramid height
    for (int i = 0; i < pyramid_height; i++) {
        int row = t + i + 1;
        if (row >= rows) break;

        // Load src into local memory with halo
        int left = n - theHalo;
        int right = n + theHalo;

        // Clamp indices for halo region
        int left_clamped = left < 0 ? 0 : left;
        int right_clamped = right >= cols ? cols - 1 : right;

        // Load localSrc1 with halo region
        // We load a segment of src with halo into local memory
        // localSrc1 size should be local_size + 2*theHalo
        // local index offset by theHalo
        int local_index = local_id + theHalo;

        // Load main data
        if (n < cols)
            localSrc1[local_index] = src[n];
        else
            localSrc1[local_index] = INT_MAX;

        // Load halo left
        if (local_id < theHalo) {
            int halo_left_index = n - theHalo;
            if (halo_left_index >= 0)
                localSrc1[local_id] = src[halo_left_index];
            else
                localSrc1[local_id] = INT_MAX;
        }

        // Load halo right
        if (local_id >= local_size - theHalo) {
            int halo_right_index = n + theHalo;
            if (halo_right_index < cols)
                localSrc1[local_index + theHalo] = src[halo_right_index];
            else
                localSrc1[local_index + theHalo] = INT_MAX;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        // Compute min for dst[n]
        if (n < cols) {
            int min_val = localSrc1[local_index];
            if (local_index - 1 >= 0)
                min_val = min(min_val, localSrc1[local_index - 1]);
            if (local_index + 1 < local_size + 2 * theHalo)
                min_val = min(min_val, localSrc1[local_index + 1]);

            dst[n] = wall[row * cols + n] + min_val;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        // Swap src and dst pointers for next iteration
        // But since pointers are passed from host, we just copy dst to src for next iteration
        // So copy dst to src for next iteration except last iteration
        if (i < pyramid_height - 1) {
            if (n < cols) {
                src[n] = dst[n];
            }
            barrier(CLK_LOCAL_MEM_FENCE);
        }
    }
}
